#!/usr/bin/env node

const https = require('https');

// 从配置中获取的信息
const appId = 'cli_a93e43ed3bf89bef';
const appSecret = 'Tk4owhBr2dPo3r6MUPmhibM2gwVLmgye';
const receiveId = 'ou_c245b0a7dff537eebcea4624964b0c90';

// 第一步：获取 tenant_access_token
function getTenantAccessToken() {
  return new Promise((resolve, reject) => {
    const postData = JSON.stringify({
      app_id: appId,
      app_secret: appSecret
    });

    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: '/open-apis/auth/v3/tenant_access_token/internal',
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(postData)
      }
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => {
        try {
          const result = JSON.parse(data);
          if (result.code === 0) {
            resolve(result.tenant_access_token);
          } else {
            reject(new Error(`获取token失败: ${JSON.stringify(result)}`));
          }
        } catch (e) {
          reject(e);
        }
      });
    });

    req.on('error', reject);
    req.write(postData);
    req.end();
  });
}

// 第二步：发送消息
function sendMessage(token) {
  return new Promise((resolve, reject) => {
    const postData = JSON.stringify({
      receive_id: receiveId,
      msg_type: 'text',
      content: JSON.stringify({
        text: '嘿！我刚才给你打印了一张照片 📸✨'
      })
    });

    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: '/open-apis/im/v1/messages?receive_id_type=open_id',
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`,
        'Content-Length': Buffer.byteLength(postData)
      }
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => {
        console.log('发送结果:', data);
        resolve(data);
      });
    });

    req.on('error', reject);
    req.write(postData);
    req.end();
  });
}

// 执行
getTenantAccessToken()
  .then(token => {
    console.log('获取到token:', token.substring(0, 20) + '...');
    return sendMessage(token);
  })
  .then(() => {
    console.log('消息发送成功！');
  })
  .catch(err => {
    console.error('错误:', err.message);
    process.exit(1);
  });

